import { Component, Input, OnInit } from '@angular/core';
import { AllMasterworksPaged, Masterwork, MasterworkItems, MasterworkView } from '../../models/masterwork.model';
import { MasterworkService } from '../../services/masterwork.service';
import { catchError, delay, first, map, shareReplay, switchMap, tap } from 'rxjs/operators';
import { Favourite, FavouriteItems } from '../../models/favourite.model';
import { MatDialog } from '@angular/material/dialog';
import { ArtItemDialogData, ArtItemDialogrefComponent } from '../../dialogref/art-item/art-item-dialogref.component';
import { animate, state, style, transition, trigger } from '@angular/animations';
import { TextFormats } from '../../models/format.model';
import { Observable, combineLatest, firstValueFrom, merge } from 'rxjs';
import { SettingsService } from '../../services/settings.service';
import { NgxSpinnerService } from 'ngx-spinner';
import { of } from 'rxjs';
import { FavouriteService } from '../../services/favourite.service';
import { MenuItem } from '../../models/menu.model';
import { TempCacheService } from '../../services/tempCacheService';
import { AccountService } from '../../modules/account/account.service';
import { Page } from '../../models/page.model';

@Component({
  selector: 'app-common-entity',
  templateUrl: './common-entity.component.html',
  styleUrls: ['./common-entity.component.scss'],
  animations: [
    trigger('detailExpand', [
    state('collapsed', style({ height: '0px', minHeight: '0' })),
    state('expanded', style({ height: '*' })),
    transition('expanded <=> collapsed', animate('225ms cubic-bezier(0.4, 0.0, 0.2, 1)')),
    ])
  ],
  standalone:false
})
export class CommonEntityComponent implements OnInit {

  @Input() menu: MenuItem[];

  currentSubmenuName$: Observable<string | null>

  arts$: Observable<MasterworkView[]>;
  origArts$: Observable<Masterwork[]>;
  textFormats: TextFormats;
  favourites$: Observable<Favourite[]>
  favouritesToAdd: number[] = [];
  favouritesToRemove: number[] = [];
  curFavourites$: Observable<FavouriteItems | null>;

  isSignedIn$: Observable<boolean> = this.accountService.isSignedIn$;

  constructor(
    private masterworkService: MasterworkService,
    private favouriteService: FavouriteService,
    private settingsService: SettingsService,
    private dialog: MatDialog,
    private spinner: NgxSpinnerService,
    private readonly tempCacheService: TempCacheService,
    private accountService: AccountService
    ) {
   }

  ngOnInit(): void {
    this.spinner.show();
    this.getArts();
    this.getFormatting();
  }

  getFormatting(){
    const formats$ = this.settingsService.getTextFormatting()
    .pipe(
      shareReplay(1)
    );
    formats$
      .pipe(
        tap(formats => {
          this.textFormats = formats;
        }),
        first(),
        catchError(() => { this.spinner.hide(); return of([]) }),
      )
      .subscribe();
  }
  async getArts(){
    let paged: AllMasterworksPaged = { page: new Page()};
   
    this.origArts$ = await this.masterworkService.getMasterworksPaged(paged);

    const currentSubmenu$ = this.origArts$
    .pipe(
      switchMap(() => this.tempCacheService.submenu$)
    )

    this.currentSubmenuName$ = currentSubmenu$
    .pipe(
      map(submenu => submenu ? this.getMenuFullName(submenu?.uid) : null)
    )

    this.curFavourites$ = this.accountService.isSignedIn$
    .pipe(
      switchMap(signedIn => signedIn ? this.favouriteService.getFavourites() : of(null))
    )

    this.arts$ = combineLatest([
      this.origArts$,
      this.curFavourites$
      ])
      .pipe(
        switchMap(([origArts, favourites]) => this.tempCacheService.submenu$
          .pipe(
            map((submenu) => {
              if (!submenu) {
                return [origArts, favourites];
              }

              this.getMenuFullName(submenu?.uid);
              return [origArts.filter(x => x.subMenuUid == submenu.uid), favourites]
            }),
          )),
        map(([arts, favourites]) => {
          return (arts as Masterwork[]).map(art => { this.spinner.hide();
            return {
              ...art,
              favourite: !!(favourites as FavouriteItems)?.items.find(item => art.uid === item.artUid)
            } as MasterworkView; 
          })
        }),
      )
  }

  openArt(image:string){
    const maxW = "1200px";
    const maxH = "900px";
    this.dialog.open<ArtItemDialogrefComponent, ArtItemDialogData>(ArtItemDialogrefComponent, {
      maxWidth: maxW,
      maxHeight: maxH,
      data: {
        image: image, maxW: maxW, maxH: maxH
      },
    });
  }

  updateFavourite(item: MasterworkView, add: boolean){
    if(add){
      const index = this.favouritesToRemove.findIndex((value) => value == item.uid);
      if(index != -1)
        this.favouritesToRemove.splice(index,1);
      this.favouritesToAdd.push(item.uid);
      this.favouriteService.addFavourite(this.favouritesToAdd)
        .pipe(
          first(),
          catchError(() => { return of(false) }),
          tap(result => { 
            if (result.isSucceed === true) {
              this.favouritesToAdd = [];
              item.favourite = true;
            }
          })
        )
        .subscribe();
    }
    else{
      const index = this.favouritesToAdd.findIndex((value) => value == item.uid);
      if(index != -1)
        this.favouritesToAdd.splice(index,1);
      this.favouritesToRemove.push(item.uid);
      this.favouriteService.removeFavourite(this.favouritesToRemove)
        .pipe(
          first(),
          catchError(() => { return of(false) }),
          tap(result => { 
            if (result.isSucceed === true) {
              this.favouritesToRemove = [];
              item.favourite = false;
            }
          })
        )
        .subscribe();
    } 
  }

  currentItemFont(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.font;
    return x === undefined || x === null ? "Arbor" : x;
  }

  currentItemFontSize(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.fontSize;
    return x === undefined || x === null ? "20px" : x;
  }

  currentItemColor(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.color;
    return x === undefined || x === null ? "black" : x;
  }

  currentItemStyle(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.style;
    return x === undefined ? null : x;
  }

  currentItemWeight(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.weight;
    return x === undefined ? null : x;
  }

  currentItemAlign(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.align;
    return x === undefined ? null : x;
  }

  currentItemStroke(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.strokeUnderline;
    return x === undefined ? null : x;
  }

  getMenuFullName(submenuUid: number | undefined){
    if(this.menu){
      const submenuName = this.menu.find(x => x.uid == x.subMenuItems?.find(y => y.uid == submenuUid)?.menuUid)?.subMenuItems?.find(z => z.uid == submenuUid)?.name;
      const menuName = this.menu.find(x => x.uid == x.subMenuItems?.find(y => y.uid == submenuUid)?.menuUid)?.name;
      return !menuName || !submenuName ? null : `${menuName} - ${submenuName}`;
    }
    return null;
  }
}
