import { BrowserAnimationsModule } from '@angular/platform-browser/animations';

import { interceptorProviders } from './core/interceptors';
import { BrowserStorageModule } from './core/utils/storage/storage.module';
import { AlertModule } from './modules/alert/alert.module';

import { CUSTOM_ELEMENTS_SCHEMA, NgModule } from '@angular/core';
import { AccountModule } from './modules/account/account.module';
import { MaterialModule } from './material/material.module';

import { SidenavComponent } from './pages/sidenav/sidenav.component';
import { MainpageComponent } from './pages/mainpage/mainpage.component';
import { HeaderComponent } from './pages/header/header.component';
import { FooterComponent } from './pages/footer/footer.component';
import { FormsModule } from '@angular/forms';
import { NgxSpinnerModule } from 'ngx-spinner';
import { CommonModule } from '@angular/common';
import { MenuItemDialogrefComponent } from './dialogref/menu-item/menu-item-dialogref.component';
import { AdminCommonEntityComponent } from './pages/admin/admin-common-entity/admin-common-entity.component';
import { ArtItemDialogrefComponent } from './dialogref/art-item/art-item-dialogref.component';
