import { Component, Input, OnInit } from '@angular/core';
import { map, Observable } from 'rxjs';
import { UserRole, UserStore } from '../../services/user.store';
import { AccountService } from '../../modules/account/account.service';

@Component({
  selector: 'app-mainpage',
  templateUrl: './mainpage.component.html',
  styleUrls: ['./mainpage.component.scss'],
  standalone:false
})
export class MainpageComponent implements OnInit {
  
  @Input() showProfile: boolean;

  private isAdmin$: Observable<boolean>;
  isSignedIn$: Observable<boolean> = this.accountService.isSignedIn$;

  delPreloadUrl = "./../assets/images/delete24.png";
  delUrl = "assets/images/delete24.png";
  addPreloadUrl = "./../assets/images/addButton.png";
  addUrl = "assets/images/addButton.png";
  del2PreloadUrl = "./../assets/images/deleteButton.png";
  del2Url = "assets/images/deleteButton.png";
  eyeOpenPreloadUrl = "./../assets/images/eyeOpen.png";
  eyeOpenUrl = "assets/images/eyeOpen.png";
  eyeClosePreloadUrl = "./../assets/images/eyeClose.png";
  eyeCloseUrl = "assets/images/eyeClose.png";
  transparentPreloadUrl = "./../assets/images/transparent.gif";
  transparentUrl = "assets/images/transparent.gif";

  constructor(
    private userStore: UserStore,
    private accountService: AccountService
  ) {
  }

  ngOnInit(): void {
    this.isAdmin$ = this.userStore.curRole$
      .pipe(
        map(role =>  role === UserRole.ADMIN)
      );
  }
}