import { Router } from '@angular/router';
import { BehaviorSubject, firstValueFrom, Observable, of, throwError } from 'rxjs';
import { catchError, map, switchMap, tap } from 'rxjs/operators';
import { LocalStorage } from '../../core/utils/storage/interfaces/local-storage.interface';
import { ApiService } from '../../services/api.service';
import { JwtModel, SignInForm } from './account.models';
import { AlertService } from '../alert/alert.service';
import { Users } from '../../models/user.model';
import { Injectable } from '@angular/core';
import { UserService } from '../../services/user.service';
import { UserRole, UserStore } from '../../services/user.store';
import { Feedback, Feedbacks } from '../../models/feedback.model';
import { MyDetails } from '../../models/mydetails.model';
import { Subscribers } from '../../models/subscribers.model';
import { NewsletterText } from '../../models/newsletter.model';

@Injectable({providedIn: 'root'})
export class AccountService {

  private isSignedIn: BehaviorSubject<boolean> = new BehaviorSubject(false);
  isSignedIn$: Observable<boolean> = this.isSignedIn.asObservable();

  constructor(
    private router: Router,
    private apiService: ApiService,
    private _localStorage: LocalStorage,
    private alertService: AlertService,
    private userService: UserService,
    private userStore: UserStore,
  ) {
    if(this._localStorage.getItem("id_token") ){
      this.isSignedIn.next(true);

      setTimeout(() => {
        this.userService.isAdmin()
        .pipe(
          tap(isAdmin => {this.userStore.setRole(isAdmin ? UserRole.ADMIN : UserRole.USER)})
        )
        .subscribe()
      }, 0)
    } 
    else{
      this.isSignedIn.next(false);
    }
  }

  signIn(form: SignInForm): Observable<any> {
    this.alertService.clear();

    return this.apiService
      .post<JwtModel>('login', form)
      .pipe(
        tap(res => {
          this._localStorage.setItem('id_token',res.accessToken);
          this.router.navigateByUrl('/');
          this.isSignedIn.next(true);
        }),
        catchError(async (err) => {
          this.alertService.error(err.message);
          this.isSignedIn.next(false);
          this.userStore.clearRole();
          
          return of(null);
          //return throwError(() => err);
        }),
        switchMap(() => { 
          return this._localStorage.getItem('id_token') 
            ? this.userService.isAdmin()
              .pipe(
                tap(isAdmin => {this.userStore.setRole(isAdmin ? UserRole.ADMIN : UserRole.USER) }
              )
              )
            : of(null)})
    );
  }

  async signOut(): Promise<any> {

    this.alertService.clear();
    this.isSignedIn.next(false);
    this.userStore.clearRole();

    return await firstValueFrom(this.apiService
      .post<any>('logout', {})
      .pipe(
        tap((res) => {
          this._localStorage.removeItem("id_token");
          this.alertService.info(res);
          this.router.navigate(['/']);
        }),
        map(() => true),
        catchError(async (err) => { this._localStorage.removeItem("id_token"); this.alertService.error(err.message ?? ' ')})
    ));
  }

  register(form: SignInForm): Observable<any> {
    this.alertService.clear();

    return this.apiService
      .post<any>('register', form)
      .pipe(
        tap((res) => {
          this.alertService.info(res);
          this.router.navigateByUrl('/');
        }),
        map(result => result),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  restorePassword(form: SignInForm): Observable<any> {
    this.alertService.clear();

    return this.apiService
      .post<any>('restore', form)
      .pipe(
        tap(res => {
          this.alertService.info(res);
          this.router.navigateByUrl('/');
        }),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  getProfile(): Observable<any>{
    this.alertService.clear();

    return this.apiService
      .get<any>('users')
      .pipe(
        tap(res => {
          this.alertService.info(res);
        }),
        map((data: Users) => data.items),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  sendFeedback(feedback: Feedback): Observable<any>{
    return this.apiService
      .post<any>('feedback', feedback)
      .pipe(
        tap(res => {
          return res;
        }),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  getFeedback(): Observable<any>{
    return this.apiService
      .get<any>('feedback')
      .pipe(
        tap(res => {
          this.alertService.info(res);
        }),
        map((data: Feedbacks) => data.items),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  sendMyDetails(details: MyDetails): Observable<any>{
    return this.apiService
    .post<any>('mydetails', details)
    .pipe(
      tap(res => {
        return res;
      }),
      catchError(async (err) => this.alertService.error(err.message))
    );
  }

  getMyDetails(): Observable<any>{
    return this.apiService
      .get<any>('mydetails')
      .pipe(
        tap(res => {
          this.alertService.info(res);
        }),
        map((data: MyDetails) => data),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  saveNewsletter(newsletter: NewsletterText): Observable<any>{
    return this.apiService
    .post<any>('newsletter', newsletter)
    .pipe(
      tap(res => {
        return res;
      }),
      catchError(async (err) => this.alertService.error(err.message))
    );
  }

  getMNewsletter(): Observable<any>{
    return this.apiService
      .get<any>('newsletter')
      .pipe(
        tap(res => {
          this.alertService.info(res);
        }),
        map((data: NewsletterText) => data),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }

  getSubscribers(): Observable<any>{
    return this.apiService
      .get<Subscribers>('subscribers')
      .pipe(
        tap(res => {
          this.alertService.info(res);
        }),
        map((data: Subscribers) => data.subscribed),
        catchError(async (err) => this.alertService.error(err.message))
      );
  }
}
