import { AbstractControl, FormControl, FormGroup, UntypedFormBuilder, Validators } from '@angular/forms';
import { Observable, ReplaySubject, Subject, catchError, delay, distinctUntilChanged, filter, first, firstValueFrom, map, of, shareReplay, takeUntil, tap } from 'rxjs';
import { AccountService } from '../../account.service';
import { User } from '../../../../models/user.model';
import { NgxSpinnerService } from "ngx-spinner";
import { UserService } from '../../../../services/user.service';
import { UserProfileForm } from '../../account.models';
import { animate, state, style, transition, trigger } from '@angular/animations';
import { MatPaginator } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { MatSort } from '@angular/material/sort';
import { Component, OnDestroy, OnInit, ViewChild } from '@angular/core';
import { FileHandle } from '../../../../dragdrop/drag.directives';
import { FavouriteService } from '../../../../services/favourite.service';
import { Favourite } from '../../../../models/favourite.model';
import { MasterworkService } from '../../../../services/masterwork.service';
import { Masterwork, MasterworkItems, MasterworksByUidsPaged } from '../../../../models/masterwork.model';
import { TextFormats } from '../../../../models/format.model';
import { SettingsService } from '../../../../services/settings.service';
import { MenuItem } from '../../../../models/menu.model';
import { MenuService } from '../../../../services/menu.service';
import { ArtItemDialogData, ArtItemDialogrefComponent } from '../../../../dialogref/art-item/art-item-dialogref.component';
import { MatDialog } from '@angular/material/dialog';
import { UserRole, UserStore } from '../../../../services/user.store';
import { FeedbackMessage } from '../../../../models/feedback.model';
import { FeedbackMessageDialogData, FeedbackMessageDialogrefComponent } from '../../../../dialogref/feedback-message/feedback-message-dialogref.component';
import { Page } from '../../../../models/page.model';

type UserFormType = {
  name: FormControl<string>;
  familyName: FormControl<string | null>;
  password: FormControl<string>;
  phone: FormControl<string | null>;
  email: FormControl<string>;
  subscription: FormControl<boolean>;
};

@Component({
  selector: 'app-user-profile',
  templateUrl: './user-profile.component.html',
  styleUrls: ['./user-profile.component.scss'],
  animations: [
    trigger('detailExpand', [
    state('collapsed', style({ height: '0px', minHeight: '0' })),
    state('expanded', style({ height: '*' })),
    transition('expanded <=> collapsed', animate('225ms cubic-bezier(0.4, 0.0, 0.2, 1)')),
    ]),
  ],
  standalone:false
})
export class UserProfileComponent implements OnInit, OnDestroy{
  private componentDestroy = new Subject<void>;

  @ViewChild(MatPaginator) paginator!: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;
  @ViewChild(MatPaginator) feedbackPaginator!: MatPaginator;
  @ViewChild(MatSort) feedbackSort: MatSort;
  @ViewChild('adminFeedbackPaginator') adminFeedbackPaginator!: MatPaginator;
  @ViewChild("adminFeedbackSort") adminFeedbackSort: MatSort;


  userProfileForm: FormGroup<UserFormType>;
  name: string;
  familyName: string | null;
  phone: string | null;
  password: string;
  subscription: boolean;
  avatar: string | null;
  
  hidePass = true;
  isAdmin$: Observable<boolean | null>;
  formData: UserProfileForm;
  users: User[];
  
  columnsToDisplay = ['name', 'familyName', 'email'];
  columnsToDisplayName = {name:'Имя', familyName: 'Фамилия', email: 'Почта'};
  dataSource: MatTableDataSource<User>;

  files: FileHandle[];
  fileUploadMessage = 'Переместите файл сюда';
  base64Output : string | null;

  favourites: Favourite[];
  favouritesToRemove: number[] = [];
  arts: Masterwork[];
  textFormats: TextFormats;
  menu: MenuItem[];

  feedbackToDisplay = ['askedDateTime', 'message'];
  feedbackToDisplayName = {askedDateTime:'Дата', message: 'Сообщение'};
  feedbackDataSource: MatTableDataSource<FeedbackMessage>;

  adminFeedbackToDisplay = ['userFullName', 'userEmail', 'askedDateTime', 'sentDateTime', 'message'];
  adminFeedbackToDisplayName = {userFullName: 'Пользователь', userEmail: 'email', askedDateTime:'Дата вопроса', sentDateTime: 'Дата отправки', message: 'Сообщение'};
  adminFeedbackDataSource: MatTableDataSource<FeedbackMessage>;
  
  _isAdmin: boolean;

  constructor(
    private formBuilder: UntypedFormBuilder,
    private accountService: AccountService,
    private spinner: NgxSpinnerService,
    private userService: UserService,
    private favouriteService: FavouriteService,
    private settingsService: SettingsService,
    private masterworkService: MasterworkService,
    private menuService: MenuService,
    public dialog: MatDialog,
    private userStore: UserStore
    )
  {    
  }
  
  ngOnInit(): void {
    const profiles$ = this.accountService.getProfile()
        .pipe(
          catchError(() => {this.spinner.hide(); return of([]) }),
          shareReplay(1)
        );

    this.isAdmin$ = this.userStore.curRole$
        .pipe(
          map(role =>  role === UserRole.ADMIN)
        );

    profiles$
        .pipe(
          filter(users => !!users),
          delay(1000),
          tap(users => {
                this.base64Output = users[0].avatar;
                this.users = users;
                this.updateForm(users[0]);
                this.tabSelectionChanged(0);
              }),
          first()
        )      
        .subscribe();

    this.getFavourites();
    this.getMenu();
    this.createForm();
    
    this.userProfileForm.statusChanges
        .pipe(
          takeUntil(this.componentDestroy),
          distinctUntilChanged(),
          tap(() => this.isButtonDisabled())
        )
        .subscribe();
    
    this.userService.isAdmin()
      .pipe(
        tap(isAdmin => this._isAdmin = isAdmin))
      .subscribe()
  }

  tabSelectionChanged(event){
    if(event == 0 && this._isAdmin){
      this.getUsers();
    }
    if(event == 1){
      this.getFeedback();
   }
  }
  getUsers(){
    this.dataSource = new MatTableDataSource<User>(this.users);
    this.dataSource.sort = this.sort;
    this.dataSource.paginator = this.paginator;
  }
  getFeedback(){
    this.accountService.getFeedback()
      .pipe(
        catchError(() => { return of([]) }),
        shareReplay(1),
        tap(messages => {
          if(this._isAdmin){
            this.adminFeedbackDataSource = new MatTableDataSource<FeedbackMessage>(messages);
            this.adminFeedbackDataSource.sort = this.adminFeedbackSort;
            this.adminFeedbackDataSource.paginator = this.adminFeedbackPaginator;
          }
          else {
            this.feedbackDataSource = new MatTableDataSource<FeedbackMessage>(messages);
            this.feedbackDataSource.sort = this.feedbackSort;
            this.feedbackDataSource.paginator = this.feedbackPaginator;
          }}),
        first()
      )      
      .subscribe();
  }

  ngOnDestroy():void{
    this.componentDestroy.next();
    this.componentDestroy.complete();
  }
 
  getFavourites(){
    this.spinner.show();
    const favourites$ = this.favouriteService.getFavourites()
    .pipe(
      shareReplay(1)
    );
    favourites$
      .pipe(
        tap(result => {
          this.favourites = result.items;
          this.getArts(this.favourites);
          this.getFormatting(this.favourites);
        }),
        first(),
        catchError(() => { return of([]) }),
      )
      .subscribe();
  }
  
  async getArts(favourites: Favourite[]){
    let paged: MasterworksByUidsPaged = { uids: favourites.map(element => element.artUid), page: new Page()};
    let totalCount = 0;
    let currentCount = 0;
    const page = await firstValueFrom(this.masterworkService.getMasterworkByUids(paged));
    totalCount = page.totalCount;
    currentCount += page.items.length;
    const pagesPromises: Promise<MasterworkItems>[] = [];
    
    while(totalCount > currentCount){
      paged.page.pageNumber++;
      currentCount += page.items.length;
      pagesPromises.push(firstValueFrom(this.masterworkService.getMasterworkByUids(paged)))
    }

    let pages = await Promise.all(pagesPromises);
    pages = [page, ...pages];

    const files$ = of(pages.flatMap((page) => page.items ))
    .pipe(
      first(),
      shareReplay(1)
    );
    files$
      .pipe(
        tap(result => {
          this.arts = result;
          this.spinner.hide();
        }),
        first(),
        catchError(() => {this.spinner.hide(); return of([]) }),
      )
      .subscribe();
  }

  getFormatting(favourites: Favourite[]){
    const formats$ = this.settingsService.getTextFormattingByArtUids(favourites.map(element => element.artUid))
    .pipe(     
      shareReplay(1)
    );
    formats$
      .pipe(
        tap(formats => {
          this.textFormats = formats;
          this.spinner.hide();
        }),
        first(),
        catchError(() => {this.spinner.hide(); return of([]) }),
      )
      .subscribe();
  }

  getMenu(){
    const menu$ = this.menuService.getMenu()
      .pipe(
        catchError(() => { return of([]) }),
        shareReplay(1)
      );

    menu$
      .pipe(
        tap(menu => {
          this.menu = menu;
        }),
        first()
      )
      .subscribe();
  }

  applyFilter(event: Event) {
    const filterValue = (event.target as HTMLInputElement).value;
    this.dataSource.filter = filterValue.trim().toLowerCase();

    if (this.dataSource.paginator) {
      this.dataSource.paginator.firstPage();
    }
  }

  toggleRow(element: { expanded: boolean; }) {
    element.expanded = !element.expanded
  }

  manageAllRows(flag: boolean) {
    this.users.forEach(row => {
      row.expanded = flag;
    })
  }

  isButtonDisabled() {
    return  this.name === this.userProfileForm.value.name
            && this.familyName === this.userProfileForm.value.familyName
            && this.phone === this.userProfileForm.value.phone
            && this.password === this.userProfileForm.value.password
            && this.subscription === this.userProfileForm.value.subscription
            && this.avatar === this.base64Output
            && this.favouritesToRemove.length === 0;
  }

  onSubmit(): void {
    if (this.userProfileForm.valid) {
      this.formData = {
        name: this.userProfileForm.value.name,
        familyName:  this.userProfileForm.value.familyName,
        password: this.userProfileForm.value.password,
        phone: this.userProfileForm.value.phone,
        subscription: this.userProfileForm.value.subscription,
        avatar: this.base64Output
      };
      this.userService.updateUserInfo(this.formData).subscribe();

      this.name = this.userProfileForm.value.name!;
      this.familyName =  this.userProfileForm.value.familyName ?? null;
      this.password =  this.userProfileForm.value.password!;
      this.phone = this.userProfileForm.value.phone ?? null;
      this.subscription = this.userProfileForm.value.subscription!;
      this.avatar = this.base64Output;
      
      if(this.favouritesToRemove.length > 0){
        this.favouriteService.removeFavourite(this.favouritesToRemove)
          .pipe(
            first(),
            catchError(() => { return of(false) }),
            tap(result => { 
              if (result.isSucceed === true) {
                this.favouritesToRemove = [];
                this.getFavourites();
              }
            })
          )
          .subscribe();
      }
    }
  }
  
  get _userpassword(): AbstractControl {
    return this.userProfileForm.get('password')!;
  }
  get _username(): AbstractControl {
    return this.userProfileForm.get('name')!;
  }
  get _userfamilyName(): AbstractControl {
    return this.userProfileForm.get('familyName')!;
  }
  get _userphone(): AbstractControl {
    return this.userProfileForm.get('phone')!;
  }
  get _subscription(): AbstractControl {
    return this.userProfileForm.get('subscription')!;
  }

  private createForm(): void {
    this.spinner.show();
    this.userProfileForm = this.formBuilder.group({
      password: ['', [Validators.required]],
      phone: ['', [Validators.pattern('[- +()0-9]+')]],
      name:  ['', [Validators.required]],
      email:  [''],
      familyName:  [''],
      subscription: [false]
    });
  }

  private updateForm(user: User):void{
    this.spinner.hide();

    this.userProfileForm
      .patchValue(
        {
          password: user.password,
          phone: user.phone ?? '',
          name: user.name,
          familyName: user.familyName ?? '',
          email: user.email,
          subscription: user.subscription
        });
      this.name = user.name;
      this.familyName = user.familyName ?? '';
      this.phone = user.phone ?? '';
      this.password = user.password;
      this.subscription = user.subscription;
      this.avatar = user.avatar;
  }
  
  filesDropped(files: FileHandle[]): void {
    var mimeType = files[0].file.type;
    if (mimeType.match(/image\/*/) == null) {
      this.fileUploadMessage = "Поддерживаются только изображения";
      return;
    }
    if(files[0].file.size > 1048576){
      this.fileUploadMessage = "Размер аватара не должен превышать 1 Мб";
      return;
    }
    this.onFileSelected(files);
  }
  onFileSelected(files: FileHandle[]) {
    this.convertFile(files).subscribe(base64 => {
      this.base64Output = base64;
    });
  }  
  convertFile(files: FileHandle[]) : Observable<string> {
    const result = new ReplaySubject<string>(1);
    const reader = new FileReader();
    reader.readAsBinaryString(files[0].file);
    reader.onload = (event) => result.next(btoa(event.target!.result!.toString()));
    return result;
  }

  removeAvatar(): void {
    this.base64Output = '';
  }

  isFavourite(uid: number){
    return this.favourites.find(x => x.artUid == uid) === undefined ? false : true;
  }
  updateFavourite(uid: number){
    if(this.isFavourite(uid)){
      this.favouritesToRemove.push(uid);
      const i = this.favourites.findIndex((item) => item.artUid == uid);
      this.favourites.splice(i,1);
    }
    else{
      const index = this.favouritesToRemove.findIndex((value) => value == uid);
      if(index != -1)
        this.favouritesToRemove.splice(index,1);
      const i = this.favourites.findIndex((item) => item.artUid == uid);
      this.favourites.push({artUid: uid});
    }
  }

  getMenuFullName(submenuUid: number){    
    const submenuName = this.menu?.find(x => x.subMenuItems?.filter(y => y.uid == submenuUid))?.subMenuItems?.find(z => z.uid == submenuUid)?.name;
    const menuName = this.menu?.find(x => x.uid == x.subMenuItems?.find(y => y.uid == submenuUid)?.menuUid)?.name;
    return !menuName ? "" : `Меню:  ${menuName} / ${submenuName}`;
  }

  currentItemFont(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.font;
    return x === undefined || x === null ? "Arbor" : x;
  }
  
  currentItemFontSize(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.fontSize;
    return x === undefined || x === null ? "20px" : x;
  }
  
  currentItemColor(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.color;
    return x === undefined || x === null ? "black" : x;
  }
  
  currentItemStyle(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.style;
    return x === undefined ? null : x;
  }
  
  currentItemWeight(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.weight;
    return x === undefined ? null : x;
  }
  
  currentItemAlign(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.align;
    return x === undefined ? null : x;
  }
  
  currentItemStroke(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats?.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.strokeUnderline;
    return x === undefined ? null : x;
  } 

  openArt(image:string){
    const maxW = "1200px";
    const maxH = "900px";
    this.dialog.open<ArtItemDialogrefComponent, ArtItemDialogData>(ArtItemDialogrefComponent, {
      maxWidth: maxW,
      maxHeight: maxH,
      data: {
        image: image, maxW: maxW, maxH: maxH
      },
    });
  }

  openFeedback(element:any){
    const maxW = "900px";
    const maxH = "600px";
    this.dialog.open<FeedbackMessageDialogrefComponent, FeedbackMessageDialogData>(FeedbackMessageDialogrefComponent, {
      maxWidth: maxW,
      maxHeight: maxH,
      data: {
        message: element[this._isAdmin ? this.adminFeedbackToDisplay[4] : this.feedbackToDisplay[1]], 
        date: element[this._isAdmin ? this.adminFeedbackToDisplay[2] : this.feedbackToDisplay[0]], 
        width: maxW, 
        height: maxH
      },
    });
  }

  applyFeedbackFilter(event: Event) {
    const filterValue = (event.target as HTMLInputElement).value;
    if(this._isAdmin){
      this.adminFeedbackDataSource.filter = filterValue.trim().toLowerCase();
      if (this.adminFeedbackDataSource.paginator) {
        this.adminFeedbackDataSource.paginator.firstPage();
      }
    }
    else{
      this.feedbackDataSource.filter = filterValue.trim().toLowerCase();
      if (this.feedbackDataSource.paginator) {
        this.feedbackDataSource.paginator.firstPage();
      }
    }
  }

  isDate = (value: any): boolean => {
    const date = new Date(value);
    return date instanceof Date && !isNaN(date.getTime())
  };
}
