import { Injectable } from "@angular/core";
import { ApiService } from "./api.service";
import { BehaviorSubject, Observable, catchError, map, of, tap } from "rxjs";
import { TextFormats } from "../models/format.model";
import { WatermarkSettings } from "../models/watermark.model";
import { BackgroundItems, NewBackgroundItem } from "../models/background.model";

@Injectable({
    providedIn: 'root',
  })
  export class SettingsService {
  
  private curBgnd = new BehaviorSubject<string>("");
  curBgnd$: Observable<string> = this.curBgnd.asObservable();

  constructor(
    private apiService: ApiService
  ) {
    this.initBackground();
  }
  
  getTextFormatting(): Observable<any> {
    return this.apiService
      .get<any>('settings/text-formatting')
      .pipe(
        map((data: TextFormats) => data),
        catchError(() => of() as Observable<any>));
  }

  getTextFormattingByArtUids(uids: number[]): Observable<any> {
    return this.apiService
      .post<any>('settings/text-formatting/by-arts', uids)
      .pipe(
        map((data: TextFormats) => data),
        catchError(() => of() as Observable<any>));
  }

  updateTextFormatting(textFormats: TextFormats): Observable<any> {
    return this.apiService
      .put<TextFormats>('settings/text-formatting', textFormats)
      .pipe(          
        catchError(() => of() as Observable<any>));
  }

  getWatermarkSettings(): Observable<any> {
    return this.apiService
      .get<any>('settings/watermark')
      .pipe(
        map((data: WatermarkSettings) => data),
        catchError(() => of() as Observable<any>));
  }

  updateWatermarkSettings(settings: WatermarkSettings): Observable<any> {
    return this.apiService
      .put<WatermarkSettings>('settings/watermark', settings)
      .pipe(
        catchError(() => of() as Observable<any>));
  }

  initBackground(){
    this.getBackground()
      .pipe(
        tap(data  => {
          let bgnd: string | undefined
          if(data && data.items && data.items.some(x => x.isActive)){
            bgnd = data.items.find(x => x.isActive)?.image;
          }

          if(bgnd && bgnd?.length > 0){
            this.curBgnd.next(bgnd);
          } else{
            this.curBgnd.next("'assets/images/background.jpg'");
          }
        }),
        catchError(() => of() as Observable<any>)
      )
      .subscribe()
  }

  getBackground(): Observable<BackgroundItems>{
    return this.apiService
      .get<any>('settings/background')
      .pipe(
        map((data: BackgroundItems) => data),
        catchError(() => of() as Observable<any>));
  }

  addBackground(image: NewBackgroundItem): Observable<any>{
    return this.apiService
      .post<any>('settings/background', image)
      .pipe(
        catchError(() => of() as Observable<any>));
  }

  updateBackground(items: BackgroundItems): Observable<any>{
    return this.apiService
      .put<any>('settings/background', items)
      .pipe(
        catchError(() => of() as Observable<any>));
  }
}