import { HttpErrorResponse, HttpEvent, HttpHandler, HttpInterceptor, HttpRequest } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Router } from '@angular/router';
import { Observable, throwError } from 'rxjs';
import { catchError, tap } from 'rxjs/operators';
import { environment } from '../../../environments/environment';
import { AnonymGuard } from '../guards/anonym.guard';
import { AuthGuard } from '../guards/auth.guard';
import { LocalStorage } from '../utils/storage/interfaces/local-storage.interface';
import { AccountService } from '../../modules/account/account.service';
import { AlertService } from '../../modules/alert/alert.service';
import { BaseErrorResponse } from '../../services/api.service';
import { ValidationErrors } from '@angular/forms';

  @Injectable()
  export class AuthInterceptor implements HttpInterceptor {
    private readonly _anonymUrls: string[] = [
      '/'
    ];
  
    constructor(
      private _router: Router,
      private _authGuard: AuthGuard,
      private _anonymGuard: AnonymGuard,
      private _localStorage: LocalStorage,
      private _alertService: AlertService,
      private _accountService: AccountService
    ) {}
  
    intercept(
      request: HttpRequest<unknown>,
      next: HttpHandler
    ): Observable<HttpEvent<unknown>> {
   
    const idToken = this._localStorage.getItem("id_token"); 

    if (idToken) {
        const cloned = request.clone({
              headers: request.headers.set("Authorization", "Bearer " + idToken)
        });

        request = cloned;
    }

    return next.handle(request)
      .pipe(       
          catchError((err: HttpErrorResponse) => {
            switch (err.status) {
              case 401:
                this._accountService.isSignedIn$
                  .pipe(
                    tap(signedin => 
                      {
                        if(signedin)
                          this._accountService.signOut();
                      }))
                  .subscribe()
                break;
              case 402:
              case 403:
                if (
                  this._anonymUrls.find((url: string) =>
                    this._router.url.includes(url)
                  ) == null &&
                  !this._authGuard.isRunning &&
                  !this._anonymGuard.isRunning
                ) {
                  if (environment.loginRedirect) {
                  //   window.location.replace(
                  //     `${
                  //       environment.loginRedirect
                  //     }?backURL=${window.encodeURIComponent(window.location.href)}`
                  //   );
                  // } else {
                    this._router.navigateByUrl(this._anonymUrls[0], {
                      state: { redirect: this._router.url },
                    });                    
                  }
                }
                break;
              case 500:
                this._alertService.error("Возникла ошибка.");
                break;

              default:
                this._alertService.error(err.message);
                break;
            }
            
            return throwError(() => new Error(err.error));
        })
      );
    }
  }
  