import { Component, Input, OnInit } from "@angular/core";
import { first, of, switchMap, tap } from "rxjs";
import { CdkDragDrop, moveItemInArray} from '@angular/cdk/drag-drop';
import { MenuItem, MenuItems, SubMenuItem } from "../../../models/menu.model";
import { v4 as uuidv4 } from 'uuid';
import { MatDialog } from "@angular/material/dialog";
import { MenuItemDialogrefComponent } from "../../../dialogref/menu-item/menu-item-dialogref.component";
import { MenuService } from "../../../services/menu.service";
import { NgxSpinnerService } from "ngx-spinner";
import { animate, state, style, transition, trigger } from "@angular/animations";

@Component({
  selector: 'app-admin-menu-entity',
  templateUrl: './admin-menu-entity.component.html',
  styleUrls: ['./admin-menu-entity.component.scss'],
  animations: [
    trigger('detailExpand', [
    state('collapsed', style({ height: '0px', minHeight: '0' })),
    state('expanded', style({ height: '*' })),
    transition('expanded <=> collapsed', animate('225ms cubic-bezier(0.4, 0.0, 0.2, 1)')),
    ]),
  ], 
  standalone:false
})
export class AdminMenuEntityComponent implements OnInit {
  @Input() menu: MenuItem[];
  @Input() origMenu: MenuItem[];
 
  menues: MenuItems = {items: []};
  menuChanged: boolean = false;
  clicked: {[key: number]: boolean} = {};
  removeMenu: boolean = false;
  currentMenu: MenuItem | null;

  subMenu: SubMenuItem[] = [];
  removeSubMenu: boolean = false;
  currentSubMenu: SubMenuItem | null;
  clickedSub: {[key: number]: boolean} = {};
  
  constructor(
    public dialog: MatDialog,
    private menuService: MenuService,
    private spinner: NgxSpinnerService
    ) {      
  }

  ngOnInit(): void {
    this.spinner.show();
  }

  onMenuSubmit(){
    if(this.menu){
      for( let i = 0; i < this.menu!.length; i ++){
        this.menu![i].position = i

        if(this.menu![i].subMenuItems && this.menu![i].subMenuItems!.length > 0){
          for(let j = 0; j < this.menu![i].subMenuItems!.length; j ++)
            this.menu![i].subMenuItems![j].position = j
          this.menu![i].isActive = this.menu![i].subMenuItems!.filter(x => x.isActive === true).length > 0 && this.menu![i].isActive;
        }
        else{
          this.menu![i].isActive = false;
        }
      }

      this.menues.items = this.menu;
      this.menuService.updateMenu(this.menues)
      .pipe(
        tap(menu => {
          this.menues = menu ?? [];
        }),
        first()
      ).subscribe();
    }
    this.menuChanged = false;
  }
 
  drop(event: CdkDragDrop<string[]>) {
    moveItemInArray(this.menu!, event.previousIndex, event.currentIndex);
    this.menuChanged = this.objectsEqual(this.origMenu, this.menu);
    this.onMenuClick(event.currentIndex, this.menu![event.currentIndex]);
  }

  onMenuClick(i: number, item: MenuItem){
    this.clicked = {};
    this.clicked[i] = !this.clicked[i];
    this.removeMenu = true;
    this.currentMenu = item;
    this.subMenu = item.subMenuItems ?? [];
    this.removeSubMenu = false;
    this.clickedSub = {};
  }

  onMenuDoubleClick(i: number,item: MenuItem){
    this.dialog.open(MenuItemDialogrefComponent, {
        data: item,
        autoFocus: true,
        width: '400px'
      })
      .afterClosed()
        .pipe(
          first(),
          switchMap(result => {
            if(result)
            {
              item.name = result.name;
              item.isActive = result.isActive;
              this.menuChanged = this.objectsEqual(this.origMenu, this.menu);
            }
            return of(null)
          })
        )
      .subscribe();
  }

  onMenuAdd(){
    this.dialog.open(MenuItemDialogrefComponent, {
        data: [],
        autoFocus: true,
        width: '400px'
      })
      .afterClosed()
        .pipe(
          first(),
          switchMap(result => {
            if(result)
            {
              if(!this.menu)
                this.menu = [];

              let item = {
                uid: uuidv4(), 
                name: result.name,
                isActive: result.isActive,
                position: this.menu!.length,
                subMenuItems: [] };

              this.menu!.push(item);
              this.menuChanged = true;
              this.currentMenu = item;
            }
            return of(null)
          })
        )
      .subscribe();
  }

  onMenuDelete(){
    if(this.currentMenu){
      const index = this.menu!.findIndex(x=>x.uid === this.currentMenu!.uid);
      if(index != -1){
        this.currentMenu.subMenuItems = [];
        this.subMenu = [];
        this.menu!.splice(index, 1);
        this.clicked = {};
        this.menuChanged = this.objectsEqual(this.origMenu, this.currentMenu);
      }
    }
    this.removeMenu = !this.removeMenu;
    this.currentMenu = null;
  }

  dropSub(event: CdkDragDrop<string[]>) {
    moveItemInArray(this.subMenu!, event.previousIndex, event.currentIndex);
    this.menuChanged = this.objectsEqual(this.origMenu, this.menu);
    this.onSubMenuClick(event.currentIndex, this.subMenu![event.currentIndex]);
  }

  onSubMenuClick(i: number, item: SubMenuItem){
    this.clickedSub = {};
    this.clickedSub[i] = !this.clickedSub[i];
    this.removeSubMenu = true;
    this.currentSubMenu = item;
  }

  onSubMenuDoubleClick(i: number,item: any){
    this.dialog.open(MenuItemDialogrefComponent, {
        data: item,
        autoFocus: true,
        width: '400px'
      })
      .afterClosed()
        .pipe(
          first(),
          switchMap(result => {
            if(result)
            {
              item.name = result.name;
              item.isActive = result.isActive;
              this.menuChanged = this.objectsEqual(this.origMenu, this.menu);
              this.onSubMenuClick(i, item);
            }
            return of(null)
          })
        )
      .subscribe();
  }

  onSubMenuAdd(){
    this.dialog.open(MenuItemDialogrefComponent, {
        data: [],
        autoFocus: true,
        width: '400px'
      })
      .afterClosed()
        .pipe(
          first(),
          switchMap(result => {
            if(result)
            {
              if(!this.menu!.find(x=>x.uid === this.currentMenu!.uid)?.subMenuItems)
                this.menu!.find(x=>x.uid === this.currentMenu!.uid)!.subMenuItems = [];

              this.subMenu = this.menu.find(x=>x.uid === this.currentMenu!.uid)!.subMenuItems!;

              let item = {
                uid: uuidv4(),
                menuUid: this.currentMenu!.uid,
                name: result.name,
                isActive: result.isActive,
                position: this.subMenu!.length };
              this.menuChanged = true;
              this.menu!.find(x=>x.uid === this.currentMenu!.uid)!.subMenuItems!.push(item);
            }
            return of(true)
          })
        )
      .subscribe();
  }

  onSubMenuDelete(){
    if(this.currentSubMenu && this.subMenu){
      const index = this.subMenu!.findIndex(x=>x.uid === this.currentSubMenu!.uid);
      if(index != -1){
        this.subMenu!.splice(index, 1);
        this.clickedSub = {};
        this.menuChanged = this.objectsEqual(this.origMenu,this.menu);
      }

      this.removeSubMenu = !this.removeSubMenu;
    }
  }

  objectsEqual(item1: any, item2: any) : boolean {
    return JSON.stringify(item1) !== JSON.stringify(item2);
  }
}
