import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable } from 'rxjs';
import { SubMenuItem } from '../models/menu.model';

@Injectable({
  providedIn: 'root',
})
export class TempCacheService {

    private submenu = new BehaviorSubject<SubMenuItem | null>(null);

	public submenu$: Observable<SubMenuItem | null> = this.submenu.asObservable();

	get submenuSnapshot(): SubMenuItem | null {
		return this.submenu.value;
	};

	public changeSubmenuSelected(submenu: SubMenuItem | null) {
   	    this.submenu.next(submenu); 
  	}
}
