import { ChangeDetectorRef, Component, Input, NgZone, OnChanges, OnInit, SimpleChanges, ViewChild } from "@angular/core";
import { catchError, first, of, take, tap } from "rxjs";
import { GlobalConstants } from "../../../globalConstants";
import { CdkTextareaAutosize } from "@angular/cdk/text-field";
import * as lodash from "lodash";
import { fontStyleWeight } from "../../../models/watermark.model";
import { AccountService } from "../../../modules/account/account.service";
import { MatTableDataSource } from "@angular/material/table";
import { MatSort } from "@angular/material/sort";
import { MatPaginator } from "@angular/material/paginator";
import { Subscribed } from "../../../models/subscribers.model";
import { SelectionModel } from "@angular/cdk/collections";
import { provideNativeDateAdapter } from "@angular/material/core";
import { AbstractControl, FormControl, FormGroup } from "@angular/forms";
import { Newsletter, NewsletterText } from "../../../models/newsletter.model";
import { NewsletterService } from "../../../services/newsletter.service";

const today = new Date();
const month = today.getMonth();
const year = today.getFullYear();

@Component({
  selector: 'app-admin-newsletter',
  templateUrl: './admin-newsletter.component.html',
  styleUrls: ['./admin-newsletter.component.scss'],
  providers: [provideNativeDateAdapter()],
  standalone:false,
})

export class AdminNewsletterComponent implements OnInit, OnChanges {
  @ViewChild('autosize') autosize: CdkTextareaAutosize;
  @ViewChild('subscribersPaginator') subscribersPaginator!: MatPaginator;
  @ViewChild('subscribersSort') subscribersSort: MatSort;

  @Input() newsletter:  NewsletterText;
  @Input() origNewsletter:  NewsletterText;
  @Input() subscribed: Subscribed[];

  fonts = GlobalConstants.fonts;
  fontSizes = GlobalConstants.fontSizes;

  readonly newsletterDates = new FormGroup({
    start: new FormControl(today),
    end: new FormControl(today),
  });

  selectedNewsletterStyleWeight = ["",""];
  selectedNewsletterStyle = "";
  selectedNewsletterWeight = "";
  
  clearFormat = false;

  settingsChanged = false;

  subscribersToDisplay = ['checked', 'name', 'email'];
  subscribersToDisplayName = {name: 'Пользователь', email: 'email'};
  subscribersDataSource: MatTableDataSource<Subscribed>;
  selection = new SelectionModel<Subscribed>(true, []);
  
  constructor(
    private ngZone: NgZone,
    private accountService: AccountService,
    private newsletterService: NewsletterService,
    private cdr: ChangeDetectorRef
    ) {
  }

  ngOnInit(): void {
  }

  ngOnChanges(changes: SimpleChanges): void {
    if(changes.subscribed){
      this.getSubscribers();
    }
  }
  
  getSubscribers(){
    this.subscribersDataSource = new MatTableDataSource<Subscribed>(this.subscribed);
    this.subscribersDataSource.sort = this.subscribersSort;
    this.subscribersDataSource.paginator = this.subscribersPaginator;
    this.toggleAllRows();
    this.cdr.detectChanges();
    
    this.cdr.detectChanges();
  }

  applyFilter(event: Event) {
    const filterValue = (event.target as HTMLInputElement).value;
      this.subscribersDataSource.filter = filterValue.trim().toLowerCase();
      if (this.subscribersDataSource.paginator) {
        this.subscribersDataSource.paginator.firstPage();
      }
  }

  isAllCheckBoxChecked() {
    const numSelected = this.selection.selected?.length;
    const numRows = this.subscribersDataSource.data?.length;
    return numSelected === numRows;
  }
  toggleAllRows() {
    if (this.subscribed && this.subscribersDataSource.data && this.selection && this.isAllCheckBoxChecked()) {
      this.selection.clear();
      return;
    }
    this.selection.select(...this.subscribersDataSource.data);
  }
  
  get _start(): AbstractControl {
    return this.newsletterDates.get('start')!;
  }
  get _end(): AbstractControl {
    return this.newsletterDates.get('end')!;
  }

  currentItemFont() : string{
      return this.newsletter.newsletterFont;   
  }
  
  currentItemFontSize() : string{
      return this.newsletter.newsletterFontSize;  
  }
  
  currentItemColor() : string{
      return this.newsletter.newsletterFontColor;    
  }
 
  currentItemStyle(): string{
      this.selectedNewsletterStyleWeight[0] = this.fontStyleText(this.newsletter.newsletterFontStyleWeight)[0];
      return this.selectedNewsletterStyleWeight[0];   
  }
  setCurrentItemStyle(style: string){
      this.newsletter.newsletterFontStyleWeight = this.fontStyleNumber([style, this.selectedNewsletterStyleWeight[1]]);   
  }

  currentItemWeight() : string{
      this.selectedNewsletterStyleWeight[1] = this.fontStyleText(this.newsletter.newsletterFontStyleWeight)[1];
      return this.fontStyleText(this.newsletter.newsletterFontStyleWeight)[1];    
  }
  setCurrentItemWeight(weight: string){
      this.newsletter.newsletterFontStyleWeight = this.fontStyleNumber([this.selectedNewsletterStyleWeight[0], weight]);   
  }

  currentItemAlign() : string{
    return this.newsletter.newsletterAlign;
  }
  
  cleanFormat(){
    this.newsletter.newsletterFont = "Arbor";
    this.newsletter.newsletterFontSize = "20px";
    this.newsletter.newsletterFontColor = "#FFFFFF";
    this.selectedNewsletterStyleWeight = ["",""];
    this.selectedNewsletterStyle = "";
    this.selectedNewsletterWeight = "";

    this.setCurrentItemStyle(this.selectedNewsletterStyle);
    this.setCurrentItemWeight(this.selectedNewsletterWeight);
    
    this.newsletter.newsletterAlign = "left";
  }

  triggerResize() {
    // Wait for changes to be applied, then trigger textarea resize.
    this.ngZone.onStable.pipe(take(1)).subscribe(() => this.autosize.resizeToFitContent(true));
  }
  
  colorChange($event: any) {
    if(!$event.match("rgba")){
        this.newsletter.newsletterFontColor = $event;
    }
  }
  styleWeightChange(){
    const style = this.selectedNewsletterStyleWeight.find(x=>x === "italic");
    const weight = this.selectedNewsletterStyleWeight.find(x=>x === "bold");
    this.selectedNewsletterStyle = style === undefined ? "" : style;
    this.selectedNewsletterWeight = weight === undefined ? "" : weight;
    this.selectedNewsletterStyleWeight = [this.selectedNewsletterStyle, this.selectedNewsletterWeight];   

    this.setCurrentItemStyle(this.selectedNewsletterStyle);
    this.setCurrentItemWeight(this.selectedNewsletterWeight);

    this.settingsChanged = this.origNewsletter.newsletterFontStyleWeight !== this.newsletter.newsletterFontStyleWeight;
  } 
  
  fontStyleText(value: number): string[]{
    if(value === 1 )
        return ["", fontStyleWeight[fontStyleWeight.bold]];
    else if(value === 2 )
        return [fontStyleWeight[fontStyleWeight.italic], ""];
    else if(value === 3)
        return [fontStyleWeight[fontStyleWeight.italic], fontStyleWeight[fontStyleWeight.bold]];
    else
        return ["", ""];
  }
  fontStyleNumber(value: string[]): number{
    if(this.objectsEqual( value, ["", fontStyleWeight[fontStyleWeight.bold]]))
        return 1;
    else if(this.objectsEqual( value, [fontStyleWeight[fontStyleWeight.italic], ""]))
        return 2;
    else if(this.objectsEqual( value,  [fontStyleWeight[fontStyleWeight.italic], fontStyleWeight[fontStyleWeight.bold]]))
        return 3;
    else
        return 0;
  }

  updateNewsletter(newsletter: NewsletterText){
    if(!this.objectsEqual(this.origNewsletter, this.newsletter)){
      this.accountService.saveNewsletter(newsletter)
        .pipe(
          first(),
          catchError(() => { return of([]) }),
          tap(res => 
            this.newsletter = newsletter
        ))
        .subscribe();

        this.origNewsletter = lodash.cloneDeep(newsletter);
    }
  }

  sendNewsletter(){
    const newsletter: Newsletter = { 
      dateFrom: this.newsletterDates.value.start,
      dateTo: this.newsletterDates.value.end,
      users: this.selection.selected,
      newsletter: this.newsletter,
    }; 

    this.newsletterService.createNewsletter(newsletter)
      .pipe(
        first(),
        catchError(() => { return of([]) })        
      )
      .subscribe();
  }

  mm(event){
    const start = event.target.selectionStart;
    const end = event.target.selectionEnd;
    // console.warn(event.target.value.substr(start, end - start))
  }

  objectsEqual(item1: any, item2: any) : boolean {
    return JSON.stringify(item1) === JSON.stringify(item2);
  }
}
