import { Component, Input, Output, OnInit, EventEmitter, OnChanges, SimpleChanges, ElementRef, ViewChild, ViewContainerRef } from '@angular/core';

@Component({
  selector: 'circular-slider',
  templateUrl: './circular-slider.component.html',
  styleUrls: ['./circular-slider.component.scss'],
  standalone:false
})
export class CircularSliderComponent implements OnInit {

  counter;

  static _counter = 0

  private _angle: number = 0;

  @Input() diameter: number = 0;

  @Input() 
    get angle() {
        return this._angle;
    }
    set angle(deg: number) {
        this._angle = deg || 0;
        this.angleChange.emit(this._angle);
    }

  @Output() angleChange = new EventEmitter<number>();

  constructor() {
    CircularSliderComponent._counter++;
    this.counter = CircularSliderComponent._counter;
  }

  ngOnInit() {
  }
  
}