import { MaterialService } from './material/material.service';
import { Component, OnInit, Renderer2 } from '@angular/core';
import { Observable, tap } from 'rxjs';
import { SettingsService } from './services/settings.service';

@Component({
  selector: 'app-root',
  standalone:false,
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})

export class AppComponent implements OnInit{
  title = 'Eves art';
  showProfile: boolean;
  isAdmin$: Observable<boolean>;
  bgrndUrl$: Observable<string> = this.settingsService.curBgnd$;
  public bgrndUrl: string;

  constructor(
    private materialService: MaterialService,
    private renderer: Renderer2,
    private settingsService: SettingsService
  ) {
    
  }

  ngOnInit() {
    this.applyTheme();
    this.materialService.initCustomIcons();

    this.bgrndUrl$.pipe(tap(x => this.bgrndUrl = x)).subscribe();
  }

  applyTheme() {
    const containerToApplyTheme = document.querySelector('body')

    this.renderer.addClass(containerToApplyTheme, 'standard-theme')
  }

  showProfileEvent(event){
    this.showProfile = event;
  }
}
