import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Component, Inject, ViewChild } from '@angular/core';
import { CdkTextareaAutosize } from '@angular/cdk/text-field';

export interface FeedbackDialogData{
  avatar: string | null;
  width: string;
  height: string;
}

@Component({
  selector: 'app-feedback-dialogref',
  templateUrl: './feedback-dialogref.component.html',
  styleUrls: ['./feedback-dialogref.component.scss'],
  standalone:false
})

export class FeedbackDialogrefComponent {
  
  @ViewChild('autosize') autosize: CdkTextareaAutosize;
  public text = "";
  areaText = "Форма для связи. <br> Здесь Вы можете также оставить свой заказ.";

  constructor(
    public dialogRef: MatDialogRef<FeedbackDialogrefComponent>,
    @Inject(MAT_DIALOG_DATA)  public data: FeedbackDialogData
    )
  {
  }

  onSubmit(){
    this.dialogRef.close(this.text);
  }
}
