import { AfterViewInit, Component, Input, OnChanges, OnInit, SimpleChanges, ViewChild } from "@angular/core";
import { catchError, first, map, of, shareReplay, tap } from "rxjs";
import { CdkDragEnter, CdkDropList, DragRef, moveItemInArray} from '@angular/cdk/drag-drop';
import { MenuItem, SubMenuItem } from "../../../models/menu.model";
import { animate, state, style, transition, trigger } from "@angular/animations";
import { AllMasterworksPaged, Masterwork, UpdateMasterworkItems } from "../../../models/masterwork.model";
import { MasterworkService } from "../../../services/masterwork.service";
import { FavouriteService } from "../../../services/favourite.service";
import { FavouriteCount } from "../../../models/favourite.model";
import { NgxSpinnerService } from "ngx-spinner";
import { Page } from "../../../models/page.model";

@Component({
  selector: 'app-admin-sorting-entity',
  templateUrl: './admin-sorting-entity.component.html',
  styleUrls: ['./admin-sorting-entity.component.scss'],
  animations: [
    trigger('detailExpand', [
    state('collapsed', style({ height: '0px', minHeight: '0' })),
    state('expanded', style({ height: '*' })),
    transition('expanded <=> collapsed', animate('225ms cubic-bezier(0.4, 0.0, 0.2, 1)')),
    ]),
  ], 
  standalone:false
})

export class AdminSortingEntityComponent implements OnInit, AfterViewInit, OnChanges {  
  @Input() menu: MenuItem[];
  @Input() arts: Masterwork[];
  @Input() updatedArts: Masterwork[];
  @Input() currentSubmenu: SubMenuItem | null;

  @ViewChild(CdkDropList) placeholder: CdkDropList;

  private target: CdkDropList;
  private targetIndex: number;
  private source: CdkDropList;
  private sourceIndex: number;
  private dragRef: DragRef;
  
  boxWidth = '100px';
  boxHeight = '100px';
  picWidth = "95px";
  picHeight = "95px";
  
  currentArt: Masterwork;
  curFiles: UpdateMasterworkItems = {items: []};
  
  favourites: FavouriteCount[];

  change = false;

  constructor(
    private spinner: NgxSpinnerService,
    private masterworkService: MasterworkService,
    private favouriteService: FavouriteService
    ) {
  }

  ngOnInit(): void {
    this.change = false;
    const favourites$ = this.favouriteService.getFavouriteCount()
    .pipe(
      shareReplay(1)
    );
    favourites$
      .pipe(
        tap(result => {
          this.favourites = result;
        }),
        first(),
        catchError(() => {return of([]) }),
      )
      .subscribe();
  }
 
  ngOnChanges(changes: SimpleChanges): void {
    //Called before any other lifecycle hook. Use it to inject dependencies, but avoid any serious work here. 
    this.currentSubmenu = null;
  }
  ngAfterViewInit() {
    const placeholderElement = this.placeholder.element.nativeElement;

    placeholderElement.style.display = 'none';
    placeholderElement.parentNode!.removeChild(placeholderElement);
  }

  onSortingSubmit(){
    if(this.change && this.updatedArts.length > 0){
      this.spinner.show();
      if(this.currentSubmenu === null){
        for( let i = 0; i < this.updatedArts!.length; i ++){
          this.updatedArts![i].position = this.updatedArts!.length - i;
        }
      }
      else{
        for( let i = 0; i < this.updatedArts!.length; i ++){
          this.updatedArts![i].subMenuUid = this.currentSubmenu!.uid;
          this.updatedArts![i].subMenuPosition = this.updatedArts!.length - i;
        }
      }

      this.curFiles.items = this.updatedArts.map((x) => { return {uid: x.uid, text: x.text, date: x.date, description: x.description,
        position: x.position, isActive: x.isActive, delete: x.delete, subMenuUid: x.subMenuUid, subMenuPosition: x.subMenuPosition}});

      this.masterworkService.updateMasterworks(this.curFiles)
        .pipe(
          first(),
          catchError(() => { return of(false) }),
          tap(result => { 
            if (result.isSucceed === true) {
              this.getArts();
            }
        })
        )
        .subscribe();
    }

    this.change = false;
  }
  async getArts(){
    let paged: AllMasterworksPaged = { page: new Page()};
    
    const files$ = (await this.masterworkService.getMasterworksPaged(paged))
    .pipe(
      first(),
      shareReplay(1)
    );
    files$
      .pipe(
        tap(arts => {
          this.arts = arts.filter(x => !x.dateDeleted);
          this.updatedArts = arts.filter(x => !x.dateDeleted);
          this.currentSubmenu = null;
          this.spinner.hide();
        }),
        first(),
        catchError(() => {return of([]) }),
      )
      .subscribe();
  }

  onSubmenuSelected(submenu: SubMenuItem){
    this.currentSubmenu = submenu;
    if(submenu !== null){
      this.updatedArts = this.arts.filter(x => x.subMenuUid === submenu.uid);
      this.updatedArts.sort((a, b) => (a.subMenuPosition! < b.subMenuPosition! ? 1 : -1));
    }
    else{
      this.updatedArts = this.arts.sort((a, b) => (a.position! < b.position! ? 1 : -1));
    }   
  }

  resetMenu(){
    this.currentSubmenu = null;
    this.updatedArts = this.arts;
  }

  onDropListDropped() {
    if (!this.target) {
      return;
    }

    const placeholderElement: HTMLElement =
      this.placeholder.element.nativeElement;
    const placeholderParentElement: HTMLElement =
      placeholderElement.parentElement;

    placeholderElement.style.display = 'none';

    placeholderParentElement.removeChild(placeholderElement);
    placeholderParentElement.appendChild(placeholderElement);
    placeholderParentElement.insertBefore(
      this.source.element.nativeElement,
      placeholderParentElement.children[this.sourceIndex]
    );

    if (this.placeholder._dropListRef.isDragging()) {
      this.placeholder._dropListRef.exit(this.dragRef);
    }

    this.target = null;
    this.source = null;
    this.dragRef = null;

    if (this.sourceIndex !== this.targetIndex) {
      moveItemInArray(this.updatedArts, this.sourceIndex, this.targetIndex);
      this.change = true;
    }
  }
  onDropListEntered({ item, container }: CdkDragEnter) {
    if (container == this.placeholder) {
      return;
    }

    const placeholderElement: HTMLElement =
      this.placeholder.element.nativeElement;
    const sourceElement: HTMLElement = item.dropContainer.element.nativeElement;
    const dropElement: HTMLElement = container.element.nativeElement;
    const dragIndex: number = Array.prototype.indexOf.call(
      dropElement.parentElement!.children,
      this.source ? placeholderElement : sourceElement
    );
    const dropIndex: number = Array.prototype.indexOf.call(
      dropElement.parentElement!.children,
      dropElement
    );

    if (!this.source) {
      this.sourceIndex = dragIndex;
      this.source = item.dropContainer;

      placeholderElement.style.width = this.boxWidth;
      placeholderElement.style.height = this.boxHeight;

      sourceElement.parentElement!.removeChild(sourceElement);
    }

    this.targetIndex = dropIndex;
    this.target = container;
    this.dragRef = item._dragRef;

    placeholderElement.style.display = '';

    dropElement.parentElement!.insertBefore(
      placeholderElement,
      dropIndex > dragIndex ? dropElement.nextSibling : dropElement
    );

    this.placeholder._dropListRef.enter(
      item._dragRef,
      item.element.nativeElement.offsetLeft,
      item.element.nativeElement.offsetTop
    );
  }

  formatLabel(value: number): string {
    this.boxWidth = `${value}px`;
    this.boxHeight =`${value}px`;
    this.picWidth = `${value - 5}px`;
    this.picHeight = `${value - 5}px`;

    return `${value}`;
  }

  getFavouriteCount(uid: number) : number{
    const item = this.favourites?.find(x => x.artUid === uid);

    return item === undefined || item === null ? 0 : item.count;
  }

  objectsEqual(item1: any, item2: any) : boolean {
    return JSON.stringify(item1) !== JSON.stringify(item2);
  }
}
