import { ChangeDetectorRef, Component, NgZone, OnInit, ViewChild } from "@angular/core";
import { BehaviorSubject, Observable, ReplaySubject, catchError, first, of, shareReplay, take, tap } from "rxjs";
import { MenuItem, MenuItems, SubMenuItem } from "../../../models/menu.model";
import { v4 as uuidv4 } from 'uuid';
import { MatDialog } from "@angular/material/dialog";
import * as lodash from "lodash";
import { MenuService } from "../../../services/menu.service";
import { NgxSpinnerService } from "ngx-spinner";
import { FileHandle } from "../../../dragdrop/drag.directives";
import { animate, state, style, transition, trigger } from "@angular/animations";
import { MasterworkService } from "../../../services/masterwork.service";
import { GlobalConstants } from "../../../globalConstants";
import { CdkTextareaAutosize } from "@angular/cdk/text-field";
import { TextFormat, TextFormats } from "../../../models/format.model";
import { SettingsService } from "../../../services/settings.service";
import { AllMasterworksPaged, Masterwork, NewMasterwork, NewMasterworkItems, UpdateMasterworkItems } from "../../../models/masterwork.model";
import { ArtItemDialogData, ArtItemDialogrefComponent } from "../../../dialogref/art-item/art-item-dialogref.component";
import { WatermarkSettings } from "../../../models/watermark.model";
import { MyDetails } from "../../../models/mydetails.model";
import { AccountService } from "../../../modules/account/account.service";
import { Page } from "../../../models/page.model";
import { NewsletterText } from "../../../models/newsletter.model";
import { Subscribed } from "../../../models/subscribers.model";

@Component({
  selector: 'app-admin-common-entity',
  templateUrl: './admin-common-entity.component.html',
  styleUrls: ['./admin-common-entity.component.scss'],
  animations: [
    trigger('detailExpand', [
    state('collapsed', style({ height: '0px', minHeight: '0' })),
    state('expanded', style({ height: '*' })),
    transition('expanded <=> collapsed', animate('225ms cubic-bezier(0.4, 0.0, 0.2, 1)')),
    ]),
  ],
  standalone:false
})
export class AdminCommonEntityComponent implements OnInit {
  
  @ViewChild('autosize') autosize: CdkTextareaAutosize;
  
  itemText: string = "";

  origFiles: Masterwork[];
  files: Masterwork[];
  sortFiles: Masterwork[];
  fileUploadErrorMessages: string[] = []; 
  fileUploadMessage = "Переместите изображения сюда.<br>Размер каждого не более 15Мб";
  artsChanged: boolean = false;
  newFiles: NewMasterworkItems;
  curFiles: UpdateMasterworkItems;
  addFilesCount = 0;

  fonts = GlobalConstants.fonts;
  fontSizes = GlobalConstants.fontSizes;
  newTextFormats: TextFormats;
  textFormats: TextFormats;

  activeItemUid: number;

  selectedFont = "Arbor";
  selectedFontSize = "20px";
  selectedColor = "black";
  selectedStyleWeight: string[] = ["none","none"];
  selectedStyle: string | null;
  selectedWeight: string | null;
  selectedStrokeUnderline: string | null;
  selectedAlign: string | null;
  // selectedList:string | null;

  textActive = false;
  dateActive = false; 
  descActive = false;
  
  clearFormat: boolean = false;

  menues: MenuItems = {items: []};
  menu: MenuItem[] = [];
  origMenu: MenuItem[];
  menuChanged: boolean = false;
  clicked: {[key: number]: boolean} = {};
  removeMenu: boolean = false;
  currentMenu: MenuItem | null;

  subMenu: SubMenuItem[] = [];
  removeSubMenu: boolean = false;
  currentSubMenu: SubMenuItem | null;
  clickedSub: {[key: number]: boolean} = {};
  submenuIndex = 1;
  sortSubmenu: SubMenuItem | null = null;

  watermarkSettings: WatermarkSettings;
  origWatermarkSettings: WatermarkSettings;
  
  details:  MyDetails;
  origDetails:  MyDetails;

  newsletter:  NewsletterText;
  origNewsletter:  NewsletterText;
  subscribed: BehaviorSubject<Subscribed[]> = new BehaviorSubject<Subscribed[]>([]);

  constructor(
    public dialog: MatDialog,
    private menuService: MenuService,
    private spinner: NgxSpinnerService,
    private masterworkService: MasterworkService,
    private settingsService: SettingsService,
    private ngZone: NgZone,
    private accountService: AccountService,
    private cdr: ChangeDetectorRef
    ) {
      this.textFormats = { items: []};
      this.newTextFormats = { items: []};

      this.newFiles = { items: []};
      this.curFiles = { items: []};
  }

  ngOnInit(): void {
    this.spinner.show();

    this.getMenu();
    this.getArts();
    this.getFormatting();
    this.getWatermarkSettings();
    this.getMyDetails();
    this.getNewsletter();
    this.getSubscribers();
  }

  onTabChanged($event){
    if($event.index === 0){
      this.spinner.show();
      this.getArts();
    }
    if($event.index === 1){
      this.spinner.show();
      this.getMenu();
      this.getArts();
    }
    if($event.index === 3){
      this.spinner.show();
      this.getWatermarkSettings();
    }
    if($event.index === 4){
      this.spinner.show();
      this.getSubscribers();
    }
    this.sortSubmenu = null;
  }

  getMenu(){
    const menu$ = this.menuService.getMenu()
    .pipe(
      catchError(() => {this.spinner.hide(); return of([]) }),
      shareReplay(1)
    );

    menu$
      .pipe(
        tap(menu => {
          this.menu = menu ?? [];
        }),
        first()
      )
      .subscribe();

    this.origMenu = lodash.cloneDeep(this.menu);
  }
  getFormatting(){
    const formats$ = this.settingsService.getTextFormatting()
    .pipe(     
      shareReplay(1)
    );
    formats$
      .pipe(
        tap(formats => {
          this.textFormats = formats;   
          if(this.files && this.files?.length > 0 && this.textFormats && this.textFormats?.items?.length > 0){
            this.spinner.hide();
          }
        }),
        first(),
        catchError(() => {this.spinner.hide(); return of([]) }),
      )
      .subscribe();
  }
  async getArts(){
    let paged: AllMasterworksPaged = { page: new Page()};

    const files$ = (await this.masterworkService.getMasterworksPaged(paged))
    .pipe(
      first(),
      shareReplay(1)
    );
    files$
      .pipe(
        tap(arts => {
          this.files = arts;
          this.sortFiles = arts.filter(x => !x.dateDeleted);
          this.activeItemUid = this.files[0].uid;
          if(this.files && this.files?.length > 0 && this.textFormats && this.textFormats?.items?.length > 0){
            this.spinner.hide();
          }
        }),
        first(),
        catchError(() => {this.spinner.hide(); return of([]) }),
      )
      .subscribe();
    
    this.origFiles = lodash.cloneDeep(this.files);
  }
  getWatermarkSettings(){
    this.settingsService.getWatermarkSettings()    
      .pipe(
        shareReplay(1),
        tap(settings => {
          this.watermarkSettings = settings;
          this.origWatermarkSettings = lodash.cloneDeep(this.watermarkSettings);
          this.spinner.hide();
        }),
        first(),
        catchError(() => {return of([]) }),
      )
      .subscribe();
  }
  getMyDetails(){
    this.accountService.getMyDetails()
      .pipe(
        shareReplay(1),
        catchError(() => { return of([]) }),
        tap(res => {
          this.details = res;
          this.origDetails = lodash.cloneDeep(res);
      }),
      first()
      )
      .subscribe();
  }

  getNewsletter(){
    this.accountService.getMNewsletter()
      .pipe(
        first(),
        catchError(() => { return of([]) }),
        tap(res => {
          this.newsletter = res;
          this.origNewsletter = lodash.cloneDeep(res);
      }))
      .subscribe();
  }

  getSubscribers(){
    this.accountService.getSubscribers()
      .pipe(
        catchError(() => { return of([]) }),
        tap(subscribed => {
          this.subscribed.next(subscribed);
          this.spinner.hide();
         })
      )
      .subscribe();
  }

  onSubmit(){
    if(this.newFiles.items.length > 0){
      this.masterworkService.addMasterworks(this.newFiles)
      .pipe(
        first(),
        catchError(() => { return of(false) }),
        tap(result => { 
          if (result.isSucceed === true) {
            this.getArts();
            this.getFormatting();
          }
      })
      )
      .subscribe();
      this.fileUploadErrorMessages = [];
      this.newFiles.items = [];
      this.addFilesCount = 0;
    }

    if(this.artsChanged){      
      this.curFiles.items = this.files.map((x) => { return {uid: x.uid, text: x.text, date: x.date, description: x.description,
        position: x.position, isActive: x.isActive, delete: x.delete, subMenuUid: x.subMenuUid, subMenuPosition: x.subMenuPosition}});

      this.masterworkService.updateMasterworks(this.curFiles)
        .pipe(
          first(),
          catchError(() => { return of(false) }),
          tap(result => { 
            if (result.isSucceed === true) {
              this.getArts();
            }
        })
        )
        .subscribe();

      this.settingsService.updateTextFormatting(this.textFormats)
        .pipe(
          first(),
          catchError(() => { return of(false) }),
          tap(result => {
            if (result.isSucceed === true) {
              this.getFormatting();
            }
        })
        )
        .subscribe();
    }
    
    this.artsChanged = false;
  }

  deleteArt(item: Masterwork){
    item.delete = !item.delete;
    this.artsChanged = true;
  }

  hideArt(item: Masterwork){
    item.isActive = !item.isActive;
    this.artsChanged = true;
  }
  
  openArt(image:string){
    const maxW = "1200px";
    const maxH = "900px";
    this.dialog.open<ArtItemDialogrefComponent, ArtItemDialogData>(ArtItemDialogrefComponent, {
      maxWidth: maxW,
      maxHeight: maxH,
      data: {
        image: image, maxW: maxW, maxH: maxH
      },
    });
  }

  setSubmenu(submenuUid: number, item: Masterwork){
    if(item.subMenuUid != submenuUid){
      item.subMenuUid = submenuUid;
      item.subMenuPosition = null;
      this.artsChanged = true;
    }
  }
  submenuName(submenuUid: number) : string{
    return this.menu.find(x => x.subMenuItems?.find(y=> y.uid === submenuUid))?.subMenuItems?.find(x => x.uid === submenuUid) ?.name ?? "Меню";
  }
  resetMenu(item: Masterwork){
    item.subMenuUid = null;
    item.subMenuPosition = null;
    this.artsChanged = true;
  }

  currentItemFont(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.font;
    return x === undefined || x === null ? "Arbor" : x;
  }
  setCurrentItemFont(font: string, text: boolean, date: boolean, desc: boolean){
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.font = font;
  }

  currentItemFontSize(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.fontSize;
    return x === undefined || x === null ? "20px" : x;
  }
  setCurrentItemFontSize(fontSize: string, text: boolean, date: boolean, desc: boolean){
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.fontSize = fontSize;
  }

  currentItemColor(itemUid: number, text: boolean, date: boolean, desc: boolean) : string{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.color;
    return x === undefined || x === null ? "black" : x;
  }
  setCurrentItemColor(color: string, text: boolean, date: boolean, desc: boolean){
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.color = color;
  }

  currentItemStyle(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.style;
    return x === undefined ? null : x;
  }
  setCurrentItemStyle(style: string | null, text: boolean, date: boolean, desc: boolean){  
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.style = style;
  }

  currentItemWeight(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.weight;
    return x === undefined ? null : x;
  }
  setCurrentItemWeight(weight: string | null, text: boolean, date: boolean, desc: boolean){
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.weight = weight;
  }

  currentItemAlign(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.align;
    return x === undefined ? null : x;
  }
  setCurrentItemAlign(align: string | null, text: boolean, date: boolean, desc: boolean){
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.align = align;
  }

  currentItemStroke(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
    let x = this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)?.strokeUnderline;
    return x === undefined ? null : x;
  }
  setCurrentItemStroke(strokeUnderline: string | null, text: boolean, date: boolean, desc: boolean){
    this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.strokeUnderline = strokeUnderline;
  }

  // currentItemList(itemUid: number, text: boolean, date: boolean, desc: boolean) : string | null{
  //   return this.textFormats.items.find(x => x.masterworkUid === itemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.list;
  // }
  // setCurrentItemList(list: string | null, text: boolean, date: boolean, desc: boolean){
  //   this.textFormats.items.find(x => x.masterworkUid === this.activeItemUid && x.isText === text && x.isDate === date && x.isDesc === desc)!.list = list;
  // }
  setActiveField(field: string, itemUid: number){
    this.activeItemUid = itemUid;
    switch(field){
      case "text":
        this.textActive = true;
        this.dateActive = false;
        this.descActive = false;
       break;
      case "date":
        this.dateActive = true;
        this.textActive = false;
        this.descActive = false;
       break;
      case "desc":
        this.descActive = true;
        this.dateActive = false;
        this.textActive = false;
       break;
    }
    this.selectedFont = this.currentItemFont(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedFontSize = this.currentItemFontSize(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedColor = this.currentItemColor(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedStyle = this.currentItemStyle(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedWeight = this.currentItemWeight(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedStrokeUnderline = this.currentItemStroke(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedAlign = this.currentItemAlign(itemUid, this.textActive, this.dateActive, this.descActive);
    this.selectedStyleWeight = [this.selectedStyle ?? "none", this.selectedWeight ?? "none"];
    // this.selectedList = this.currentItemList(itemUid, this.textActive, this.dateActive, this.descActive);

    this.artsChanged = true;
  }

  cleanFormat(){
    this.selectedFont = "Arbor";
    this.selectedFontSize = "20px";
    this.selectedColor = "black";
    this.selectedStyleWeight = ["none","none"];
    this.selectedStyle = "";
    this.selectedWeight = "";
    this.selectedStrokeUnderline = "";
    this.selectedAlign = "";
    // this.selectedList = "";

    this.setCurrentItemFont(this.selectedFont, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemFontSize(this.selectedFontSize, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemColor(this.selectedColor, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemStyle(this.selectedStyle, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemWeight(this.selectedWeight, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemStroke(this.selectedStrokeUnderline, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemAlign(this.selectedAlign, this.textActive, this.dateActive, this.descActive);
    // this.setCurrentItemList(this.selectedList, this.textActive, this.dateActive, this.descActive);

    this.artsChanged = true;
  }
  triggerResize() {
    // Wait for changes to be applied, then trigger textarea resize.
    this.ngZone.onStable.pipe(take(1)).subscribe(() => this.autosize.resizeToFitContent(true));
    this.fontChange();
  }  
  fontChange() {
    this.setCurrentItemFont(this.selectedFont, this.textActive, this.dateActive, this.descActive)
    this.artsChanged = true;
  }
  fontSizeChange() {
    this.setCurrentItemFontSize(this.selectedFontSize, this.textActive, this.dateActive, this.descActive);
    this.artsChanged = true;
  }
  colorChange($event: any) {
    this.selectedColor = $event;
    this.setCurrentItemColor(this.selectedColor, this.textActive, this.dateActive, this.descActive);
    this.artsChanged = true;
  }
  styleWeightChange(){
    const style = this.selectedStyleWeight.find(x=>x === "italic");
    const weight = this.selectedStyleWeight.find(x=>x === "bold");
    this.selectedStyle = style === undefined ? null : style;
    this.selectedWeight = weight === undefined ? null : weight;

    this.setCurrentItemStyle(this.selectedStyle, this.textActive, this.dateActive, this.descActive);
    this.setCurrentItemWeight(this.selectedWeight, this.textActive, this.dateActive, this.descActive);
   
    this.artsChanged = true;
  }
  strikeChange(){
    this.setCurrentItemStroke(this.selectedStrokeUnderline, this.textActive, this.dateActive, this.descActive);
    this.artsChanged = true;
  }
  alignChange(){
    this.setCurrentItemAlign(this.selectedAlign, this.textActive, this.dateActive, this.descActive);
    this.artsChanged = true;
  }
  // listChange(){
  //   this.setCurrentItemList(this.selectedList, this.textActive, this.dateActive, this.descActive);
  //   this.artsChanged = true;
  // }

  deleteNewArt(item: NewMasterwork){
    const index = this.newFiles.items.findIndex((value) => value.name === item.name && value.size === item.size);
      this.newFiles.items.splice(index,1);
    this.addFilesCount -= 1;
    if(this.addFilesCount === 0){
      this.fileUploadErrorMessages = [];
      this.newFiles.items = [];
    }
  }

  filesDropped(files: FileHandle[]): void {
    this.fileUploadErrorMessages = [];
    this.addFilesCount = files.length + this.addFilesCount;
    files.forEach(file => {
      var mimeType = file.file.type;
      if (mimeType.match(/image\/*/) == null) {
        this.fileUploadErrorMessages.push(file.file.name + " не изображение");
        this.addFilesCount -= 1;
        return;
      }
      if(file.file.size > 15800000){
        this.fileUploadErrorMessages.push("Размер " + file.file.name +" превышает 15 Мб");
        this.addFilesCount -= 1;
        return;
      }
      if(this.fileExists(file.file)){
        this.fileUploadErrorMessages.push("Файл " + file.file.name +" уже существует");
        this.addFilesCount -= 1;
        return;
      }
      if(this.newFileExists(file.file)){
        this.fileUploadErrorMessages.push("Файл " + file.file.name +" уже в загрузке");
        this.addFilesCount -= 1;
        return;
      }
      
      const artUid = uuidv4();
      
      this.newTextFormats.items = [];
      this.newTextFormats.items.push({uid: uuidv4(), masterworkUid: artUid, font: this.selectedFont, fontSize: this.selectedFontSize, color: this.selectedColor,
        align: null, style: null, weight: null, strokeUnderline: null, isText: true, isDate: false, isDesc: false});
      this.newTextFormats.items.push({uid: uuidv4(), masterworkUid: artUid, font: this.selectedFont, fontSize: this.selectedFontSize, color: this.selectedColor,
        align: null, style: null, weight: null, strokeUnderline: null, isText: false, isDate: true, isDesc: false});
      this.newTextFormats.items.push({uid: uuidv4(), masterworkUid: artUid, font: this.selectedFont, fontSize: this.selectedFontSize, color: this.selectedColor,
        align: null, style: null, weight: null, strokeUnderline: null, isText: false, isDate: false, isDesc: true});
        
      this.onFileSelected(file, artUid, this.newTextFormats.items);      
    })
  }
  onFileSelected(file: FileHandle, artUid: number, formattings: TextFormat[]) {
    if(!this.newFiles.items.find(x=> x.name === file.file.name && x.size === file.file.size)){
      this.convertFile(file).subscribe(base64 => {
        this.newFiles.items.push({
          uid: artUid, pictureImage: base64, name: file.file.name, type: file.file.type, size: file.file.size, formattings: formattings, imageHeight: null, imageWidth: null
        });        
      });
    }
  }
  convertFile(file: FileHandle) : Observable<string> {
    const result = new ReplaySubject<string>(1);
    const reader = new FileReader();
    reader.readAsBinaryString(file.file);
    reader.onload = (event) => result.next(btoa(event.target!.result!.toString()));
    return result;
  }
  fileExists(file: File): boolean{
    return this.files.find(x => x.name === file.name && x.size === file.size && !x.dateDeleted) !== undefined;
  }
  newFileExists(file: File): boolean{
    return this.newFiles.items.find(x => x.name === file.name && x.size === file.size) !== undefined;
  }
 
  objectsEqual(item1: any, item2: any) : boolean {
    return JSON.stringify(item1) !== JSON.stringify(item2);
  }
}
