import { AfterViewInit, Component, EventEmitter, OnInit, Output } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { AccountService } from '../../modules/account/account.service';
import { Observable, catchError, first, map, of, shareReplay, switchMap, tap } from 'rxjs';
import { SignInComponent } from '../../modules/account/modules/sign-in/sign-in.component';
import { SubMenuItem } from '../../models/menu.model';
import { RegisterComponent } from '../../modules/account/modules/register/register.component';
import { FeedbackDialogData, FeedbackDialogrefComponent } from '../../dialogref/feedback/feedback-dialogref.component';
import { Feedback } from '../../models/feedback.model';
import { AboutMeDialogData, AboutMeDialogrefComponent } from '../../dialogref/aboutMe/aboutme-dialogref.component';
import { fontStyleWeight, MyDetails } from '../../models/mydetails.model';

@Component({
  selector: 'app-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss'],
  standalone:false
})

export class HeaderComponent implements OnInit {
 
  @Output() show: EventEmitter<Boolean> = new EventEmitter<Boolean>();

  curSubmenu: SubMenuItem | null;
  showProfile: boolean;
  profileButtonText = 'Профиль';
  
  imgPreloadUrl = "./../assets/images/palete.gif";
  imgUrl = "assets/images/palete.gif";
  
  avatar: string | null;
  details:  MyDetails;

  isSignedIn$: Observable<boolean> = this.accountService.isSignedIn$;

  constructor(
    private dialog: MatDialog,
    private accountService: AccountService,
    )
  {
  }

  ngOnInit(): void {
    this.isSignedIn$
      .pipe(
        shareReplay(1),
        tap(result => {
          if(result)
          {
            this.accountService.getProfile()
              .pipe(
                first(),
                catchError(() => { return of([]) }),
                tap(users => { this.avatar = users[0]?.avatar;})
              )
              .subscribe();
          }
        })
      )
      .subscribe();

    this.getMyDetails();
  }

  getMyDetails(){
    this.accountService.getMyDetails()
      .pipe(
        first(),
        catchError(() => { return of([]) }),
        tap(res => this.details = res)
      )
      .subscribe();
  }

  onProfile(){
    this.showProfile = !this.showProfile;

    if (this.showProfile) {
      this.profileButtonText = 'На главную'
      this.show.emit(true);
    } else {
      this.profileButtonText = 'Профиль'
      this.show.emit(false);
    }
  }

  onLogin(): void {
    this.dialog.open(SignInComponent, {
      data: {},
      autoFocus: true,
      width: '760px',
      height: '830px'
    })
    .afterClosed()
    .pipe(
      first(),
      switchMap(result => {
        if(result)
        {
          if(result.signin){
            return this.accountService.signIn(result)
              .pipe(
                map(data => data)
                );
          }
          else if(result.forgotPswd){
            return this.accountService.restorePassword(result)
              .pipe(
                map(data => !data)
                );
          }          
        }
        return of(null)
      })
      )
      .subscribe();
  }

  onRegister(): void {
    this.dialog.open(RegisterComponent, {
      data: {},
      autoFocus: true,
      width: '760px',
      height: '830px'
    })
    .afterClosed()
    .pipe(
      first(),
      switchMap(result => {
        if(result){
          return this.accountService.register(result)
            .pipe(
              map(data => !data)
              );
        }
        return of(null)
      })
      )
      .subscribe();
  }

  async onLogout(): Promise<any>{
    await this.accountService.signOut();
    this.profileButtonText = 'Профиль';
    this.showProfile = false;
    this.show.emit(false);
  }

  onFeedback(){
    const width = "600px";
    const height = "600px";
    this.dialog.open<FeedbackDialogrefComponent, FeedbackDialogData>(FeedbackDialogrefComponent, {
      width: width,
      height: height,
      data: {
        avatar: this.avatar, width: width, height: height
      },
    })
    .afterClosed()
    .pipe(
      first(),
      switchMap(result => {
        if(result){
          let feedback: Feedback = { message: result }
          return this.accountService.sendFeedback(feedback)
            .pipe(
              map(data => !data)
              );
        }
        return of(null)
      })
      )
      .subscribe();
  }

   onAboutMe(){
    this.getMyDetails();
    
    let h = this.details.aboutmeText.split("\n").length * 40;

    const width = "40vw";
    const height = h < 500 ? h + "px": "700px";
    
    this.dialog.open<AboutMeDialogrefComponent, AboutMeDialogData>(AboutMeDialogrefComponent, {
      width: width,
      height: height,
      data: {
        text: this.details.aboutmeText, 
        width: width, 
        height: height,
        align: this.details.aboutmeAlign,
        color: this.details.aboutmeFontColor,
        font: this.details.aboutmeFont,
        size: this.details.aboutmeFontSize,
        style: this.fontStyleText(this.details.aboutmeFontStyleWeight)[0],
        weight: this.fontStyleText(this.details.aboutmeFontStyleWeight)[1],
      },
    });
   }

   fontStyleText(value: number): string[]{
    if(value === 1 )
        return ["", fontStyleWeight[fontStyleWeight.bold]];
    else if(value === 2 )
        return [fontStyleWeight[fontStyleWeight.italic], ""];
    else if(value === 3)
        return [fontStyleWeight[fontStyleWeight.italic], fontStyleWeight[fontStyleWeight.bold]];
    else
        return ["", ""];
  }

  myDeatilsExist(){
    return this.details !== null && this.details !== undefined && this.details.aboutmeText != null && this.details.aboutmeText != undefined && this.details.aboutmeText.length > 0 
  }
}
