import { Injectable } from '@angular/core';
import { firstValueFrom, Observable, of } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { AllMasterworksPaged, Masterwork, MasterworkItems, MasterworksByUidsPaged, NewMasterworkItems, UpdateMasterworkItems } from '../models/masterwork.model';
import { ApiService } from './api.service';

type CacheType = {
  data: MasterworkItems;
  time: Date;
};
@Injectable({
  providedIn: 'root',
})
export class MasterworkService {

  constructor(private apiService: ApiService) {}

  getMasterworks(paged: AllMasterworksPaged): Observable<MasterworkItems> { // query: string
    return this.apiService // of({items: []} as any)
      .post<MasterworkItems>('masterworks/all', paged)
      //   {
      //       // params: query
      //     params: new HttpParams({
      //       fromObject: {
      //         searchQuery: query,
      //       },
      //     }),
      //   }
      // )
      .pipe(
        catchError(() => of() as Observable<any>)
      );
  }

  async getMasterworksPaged(paged: AllMasterworksPaged): Promise<Observable<Masterwork[]>> {
    let totalCount = 0;
    let currentCount = 0;
    const page = await firstValueFrom(this.getMasterworks(paged));
    totalCount = page.totalCount;
    currentCount += page.items.length;
    const pagesPromises: Promise<MasterworkItems>[] = [];
    
    while(totalCount > currentCount){
      paged.page.pageNumber++;
      currentCount += page.items.length;
      pagesPromises.push(firstValueFrom(this.getMasterworks(paged)))
    }

    let pages = await Promise.all(pagesPromises);
    pages = [page, ...pages];

    return of(pages.flatMap((page) => page.items ));
  }

  getMasterworkByUids(uids: MasterworksByUidsPaged): Observable<MasterworkItems> { // query: string
    return this.apiService
      .post<MasterworkItems>('masterworks/by-uids', uids)
      .pipe(
        catchError(() => of() as Observable<any>)
      );
  }

  addMasterworks(items: NewMasterworkItems): Observable<any> { 
    return this.apiService
    .post<any>('masterworks', items)
    .pipe(     
      catchError(() => of() as Observable<any>)
    );
  }

  updateMasterworks(items: UpdateMasterworkItems): Observable<any> { 
    return this.apiService
    .put<any>('masterworks', items)
    .pipe(          
      catchError(() => of() as Observable<any>));
  }
}
