import { Injectable } from "@angular/core";
import { ApiService } from "./api.service";
import { Observable, catchError, map, of, tap } from "rxjs";
import { MenuItem, MenuItems } from "../models/menu.model";

@Injectable({
    providedIn: 'root',
  })
  export class MenuService {
  
  constructor(private apiService: ApiService) {}
  
  getMenu(): Observable<MenuItem[]> {
    return this.apiService
      .get<any>('menu')
      .pipe(  
        map((data: MenuItems) => data.items),
        catchError(() => of() as Observable<MenuItem[]>));
  }

  updateMenu(items: MenuItems): Observable<any> {
    return this.apiService
      .post<MenuItems>('menu', items)
      .pipe(          
        catchError(() => of() as Observable<any>));
  }
}