import { Injectable } from "@angular/core";
import { ApiService } from "./api.service";
import { Observable, catchError, map, of } from "rxjs";
import { FavouriteCount, FavouriteCountItems, FavouriteItems } from "../models/favourite.model";

@Injectable({
    providedIn: 'root',
  })
  export class FavouriteService {

  constructor(private apiService: ApiService) {}

  getFavourites(): Observable<FavouriteItems> {
    return this.apiService
      .get<any>('masterworks/favourites')
      .pipe(  
        map((data: FavouriteItems) => data),
        catchError(() => of() as Observable<FavouriteItems>));
  }

  getFavouriteCount(): Observable<FavouriteCount[]> {
    return this.apiService
      .get<any>('masterworks/favourites-count')
      .pipe(  
        map((data: FavouriteCountItems) => data.items),
        catchError(() => of() as Observable<FavouriteCount[]>));
  }

  addFavourite(artUids: number[]): Observable<any> {
    return this.apiService
      .post<any>('masterworks/favourites', artUids)
      .pipe(
        catchError(() => of() as Observable<any>));
  }

  removeFavourite(artUids: number[]): Observable<any> {
    return this.apiService
      .put<any>('masterworks/favourites', artUids)
      .pipe(          
        catchError(() => of() as Observable<any>));
  }
}
