import { MatDialogRef} from '@angular/material/dialog';
import { AbstractControl, FormControl, FormGroup, UntypedFormBuilder, Validators } from '@angular/forms';
import { Component } from '@angular/core';

type FormType = {
    email: FormControl<string | null>;
    password: FormControl<string | null>;
    forgotPswd: FormControl<boolean>;
    signin: FormControl<boolean>;
  };
  
@Component({
  selector: 'app-sign-in',
  templateUrl: './sign-in.component.html',
  styleUrls: ['./sign-in.component.scss'],
  standalone:false
})

export class SignInComponent {

  signInForm: FormGroup<FormType>;
  hidePass = true;
  restorePass: boolean = false;
  register: boolean = false;

  imgUrl = "assets/images/palete.gif";
 
  constructor(
    private formBuilder: UntypedFormBuilder,
    public dialogRef: MatDialogRef<SignInComponent>
    )
  {
    this._createForm();
  }

  get _email(): AbstractControl {
      return this.signInForm.get('email')!;
    }
  get _password(): AbstractControl {
      return this.signInForm.get('password')!;
    }
 
  onSubmit(): void {
    this.register = false;
    this.restorePass = false;

    this._password.markAsTouched();

    if (this.signInForm.valid) {
      this.signInForm.value.signin = true;
      this.dialogRef.close(this.signInForm.value);
    }
  }

  onForgot(): void {
    this.register = false;
    this.restorePass = true;
   
    if (this.signInForm.value.email) {
      this.signInForm.value.signin = false;
      this.signInForm.value.forgotPswd = true;
      this.dialogRef.close(this.signInForm.value);
    }
  }

  private _createForm(): void {
    this.signInForm = this.formBuilder.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [this.restorePass ? Validators.nullValidator : Validators.required]],
    });
  }
}
