import { ChangeDetectorRef, Component, Input, OnDestroy, OnInit } from '@angular/core';
import { MediaMatcher } from '@angular/cdk/layout';
import { Observable, of } from 'rxjs';
import { catchError, first, shareReplay, tap } from 'rxjs/operators';
import { MenuService } from '../../services/menu.service';
import { NgxSpinnerService } from 'ngx-spinner';
import { MenuItem, SubMenuItem } from '../../models/menu.model';
import { TempCacheService } from '../../services/tempCacheService';
import { AccountService } from '../../modules/account/account.service';

@Component({
  selector: 'app-sidenav',
  templateUrl: './sidenav.component.html',
  styleUrls: ['./sidenav.component.scss'],
  standalone:false
})
export class SidenavComponent implements OnInit, OnDestroy {
 
  @Input() showProfile: boolean;
 
  private mobileQueryListener: () => void;
  public mobileQuery: MediaQueryList;
  public getScreenHeight: any;

  events: string[] = [];
  menu: MenuItem[];
  menuChanged: boolean;
  currentSubmenu: SubMenuItem | null;

  isSignedIn$: Observable<boolean> = this.accountService.isSignedIn$;
  
  constructor(
    changeDetectorRef: ChangeDetectorRef,
    media: MediaMatcher,
    public menuService: MenuService,
    private spinner: NgxSpinnerService,
    private readonly tempCacheService: TempCacheService,
    private accountService: AccountService
    )
  {
    this.mobileQuery = media.matchMedia('(max-width: 600px)');
    this.mobileQueryListener = () => changeDetectorRef.detectChanges();
    this.mobileQuery.addListener(this.mobileQueryListener);
  }

  ngOnInit(): void {
    this.spinner.show();
    const menu$ = this.menuService.getMenu()
      .pipe(
        catchError(() => {this.spinner.hide(); return of([]) }),
        shareReplay(1)
      );

    menu$
      .pipe(
        tap(menu => {
          this.menu = menu;
          this.spinner.hide();
        }),
        first()
      )
      .subscribe();
  }

  ngOnDestroy(): void {
    this.mobileQuery.removeListener(this.mobileQueryListener);
  }

  onMenuSelected(item: SubMenuItem): void{
    this.menuChanged = true;
    this.currentSubmenu = item;
    this.tempCacheService.changeSubmenuSelected(item);
  }

  onMenuReset(){
    this.menuChanged = false;
    this.currentSubmenu = null;
    this.tempCacheService.changeSubmenuSelected(null);
  }
}
