import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { FormControl, FormGroup, UntypedFormBuilder, Validators } from '@angular/forms';
import { Component, Inject } from '@angular/core';
import { MenuItemDialogRefData } from '../../models/menu.model';

type FormType = {
    name: FormControl<string>;
    isActive: FormControl<boolean>;
  };

@Component({
  selector: 'app-menu-item-dialogref',
  templateUrl: './menu-item-dialogref.component.html',
  styleUrls: ['./menu-item-dialogref.component.scss'],
  standalone:false
})

export class MenuItemDialogrefComponent {

  menuItemForm: FormGroup<FormType>;

  constructor(
    private formBuilder: UntypedFormBuilder,
    public dialogRef: MatDialogRef<MenuItemDialogrefComponent>,
    @Inject(MAT_DIALOG_DATA)  public data: MenuItemDialogRefData    
    )
  {
    this.createForm();
  }

  isDisabled(): boolean{
    return (this.data.name === this.menuItemForm.value.name
          && this.data.isActive === this.menuItemForm.value.isActive)
          || this.menuItemForm.pristine;
  }

  onSubmit(): void {
    if (this.menuItemForm.valid) {
      if(this.menuItemForm.controls.isActive.value === undefined)
        this.menuItemForm.value.isActive = false;
      this.dialogRef.close(this.menuItemForm.value);
    }
  }

  private createForm(): void {
    this.menuItemForm = this.formBuilder.group({
      isActive: [this.data.isActive ? true : false],
      name:  [this.data.name, [Validators.required]]
    });
  }
}
