import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Component, Inject, ViewChild } from '@angular/core';
import { CdkTextareaAutosize } from '@angular/cdk/text-field';

export interface FeedbackMessageDialogData{
  message: string;
  date: string;
  width: string;
  height: string;
}

@Component({
  selector: 'app-feedback-message-dialogref',
  templateUrl: './feedback-message-dialogref.component.html',
  styleUrls: ['./feedback-message-dialogref.component.scss'],
  standalone:false
})

export class FeedbackMessageDialogrefComponent {
  
  @ViewChild('autosize') autosize: CdkTextareaAutosize;
  public text = "";

  constructor(
    public dialogRef: MatDialogRef<FeedbackMessageDialogrefComponent>,
    @Inject(MAT_DIALOG_DATA)  public data: FeedbackMessageDialogData
    )
  {
    this.text = data.message.replaceAll("\n", "<br>");
  }
}
