import { MAT_DIALOG_DATA } from '@angular/material/dialog';
import { Component, Inject } from '@angular/core';

export interface AboutMeDialogData{
  text: string;
  width: string;
  height: string;
  font: string;
  size: string;
  color: string;
  style: string;
  weight: string;
  align: string;
}

@Component({
  selector: 'app-aboutme-dialogref',
  templateUrl: './aboutme-dialogref.component.html',
  styleUrls: ['./aboutme-dialogref.component.scss'],
  standalone:false
})

export class AboutMeDialogrefComponent {
  public font ="";
  
  constructor(
    @Inject(MAT_DIALOG_DATA)  public data: AboutMeDialogData
    )
  {
    this.font = data.font?.replace('-',' ');
    // this.text2 = data.text?.replaceAll("\n", "<br>");
  }
}
